// Build the Groq API request body for SQL generation
const schemaInfo = $('HTTP — Get Schema').first().json;
const webhookBody = $('Webhook — Query').first().json.body || $('Webhook — Query').first().json;
const userQuery = (webhookBody.query || '').trim();
const history = webhookBody.history || [];

if (!userQuery) throw new Error('Empty query');

// Build schema description
const cols = (schemaInfo.columns || []).map(c => {
  const cat = schemaInfo.categoricalSamples?.[c.name];
  const num = schemaInfo.numericRanges?.[c.name];
  if (cat?.length) return `  ${c.name} ${c.type}  — values: ${cat.slice(0,12).join(', ')}`;
  if (num) return `  ${c.name} ${c.type}  — range: ${num.min} – ${num.max}, avg ${num.avg}`;
  return `  ${c.name} ${c.type}`;
}).join('\n');

const schemaBlock = `Table: ${schemaInfo.tableName || 'inventory'}\nColumns:\n${cols}\nTotal rows: ${(schemaInfo.totalRows || 0).toLocaleString()}`;

const historyMsgs = history.slice(-4)
  .map(m => ({ role: m.role === 'user' ? 'user' : 'assistant', content: m.text || '' }))
  .filter(m => m.content);

const systemPrompt = `You are an expert SQLite analyst.\n\n${schemaBlock}\n\nRules:\n1. Return ONLY a valid JSON object — no markdown fences, no prose\n2. Only write SELECT statements\n3. Table name is always "inventory"\n4. Use TRIM() on TEXT columns in WHERE/GROUP BY\n5. Use ROUND(value,1) for decimals; ROUND(value,0) for money\n6. Cap non-aggregated queries with LIMIT 100\n7. For time-series, ORDER BY the time column\n8. If the query CANNOT be answered, set "error": true\n\nReturn this exact JSON shape:\n{\n  "sql": "SELECT ...",\n  "suggested_chart_type": "bar|line|pie|scatter|area",\n  "x_axis": "column_name",\n  "y_axis": "column_name",\n  "color_by": null,\n  "title": "Short title",\n  "error": false,\n  "message": ""\n}`;

const messages = [
  { role: 'system', content: systemPrompt },
  ...historyMsgs,
  { role: 'user', content: `Generate SQL for: "${userQuery}"` }
];

return [{
  json: {
    groqBody: JSON.stringify({
      model: 'llama-3.3-70b-versatile',
      messages,
      temperature: 0.05,
      max_tokens: 700
    }),
    original_query: userQuery,
    history
  }
}];

// Parse Groq SQL response
const groqResponse = $input.first().json;
const prevData = $('Code — Build SQL Prompt').first().json;

const content = groqResponse.choices?.[0]?.message?.content?.trim() || '';
const cleaned = content.replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();
const match = cleaned.match(/\{[\s\S]*\}/);

if (!match) throw new Error('Groq returned no JSON: ' + content.slice(0, 200));

let parsed;
try { parsed = JSON.parse(match[0]); }
catch (e) { throw new Error('JSON parse failed: ' + match[0].slice(0, 200)); }

return [{ json: { ...parsed, original_query: prevData.original_query, history: prevData.history } }];

// Validate SQL — SELECT only, propagate errors
const input = $input.first().json;

if (input.error) {
  return [{ json: { ...input, __skip_db: true } }];
}

if (!input.sql || !input.sql.trim().toUpperCase().startsWith('SELECT')) {
  return [{ json: {
    error: true, __skip_db: true,
    message: 'Could not generate a valid SQL query. Try rephrasing.',
    original_query: input.original_query,
    charts: []
  }}];
}

return [{ json: input }];

// Merge SQL results with metadata
const sqlMeta = $('Code — Validate SQL').first().json;
const dbResult = $input.first().json;

if (sqlMeta.error || sqlMeta.__skip_db) {
  return [{ json: { ...sqlMeta, charts: [] } }];
}

if (!dbResult.rows || dbResult.rows.length === 0) {
  return [{ json: {
    error: true,
    message: 'The query returned no results. Try broadening your filters.',
    original_query: sqlMeta.original_query,
    sql: sqlMeta.sql,
    charts: []
  }}];
}

return [{ json: {
  rows: dbResult.rows,
  row_count: dbResult.row_count,
  columns: dbResult.columns,
  sql: sqlMeta.sql,
  original_query: sqlMeta.original_query,
  suggested_chart_type: sqlMeta.suggested_chart_type,
  x_axis: sqlMeta.x_axis,
  y_axis: sqlMeta.y_axis,
  title: sqlMeta.title,
  color_by: sqlMeta.color_by,
  history: sqlMeta.history,
  error: false
}}];

// Build the Groq API request body for chart config generation
const input = $input.first().json;

if (input.error) {
  return [{ json: { ...input, __skip_chart: true } }];
}

const { rows, row_count, columns, sql, original_query, suggested_chart_type, x_axis, y_axis, title, color_by } = input;

const sampleRows = rows.slice(0, 50);
const dataKeys = columns || (sampleRows.length > 0 ? Object.keys(sampleRows[0]) : []);

const systemPrompt = `You are a senior business intelligence analyst. Given SQL query results, produce chart configuration and actionable insights.

Return ONLY a valid JSON object — no markdown, no explanation, nothing else.

Format:
{
  "charts": [
    {
      "title": "Concise title (max 8 words)",
      "chart_type": "bar|line|pie|scatter|area",
      "x_axis": "exact_column_key",
      "y_axis": "exact_column_key",
      "color_by": null,
      "insight": "2-3 sentences with specific numbers. Most surprising or actionable finding.",
      "follow_up_suggestions": ["Follow-up 1", "Follow-up 2", "Follow-up 3"]
    }
  ]
}

Chart selection rules:
- line or area: x-axis is a time dimension (year, month, date)
- pie: 2-6 categories showing distribution/share
- scatter: correlation between two numeric columns
- bar: all other cases

You MAY return 2 charts if data supports two complementary views. Never more than 2.
x_axis and y_axis MUST be exact keys from the data columns — copy verbatim.`;

const userPrompt = `Question: "${original_query}"
SQL: ${sql}
Rows: ${row_count}
Columns: ${dataKeys.join(', ')}
Suggested: ${suggested_chart_type} | x: ${x_axis} | y: ${y_axis}

Data (first ${sampleRows.length} rows):
${JSON.stringify(sampleRows)}`;

return [{
  json: {
    groqBody: JSON.stringify({
      model: 'llama-3.3-70b-versatile',
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userPrompt }
      ],
      temperature: 0.3,
      max_tokens: 1400
    }),
    rows, row_count, columns, sql, original_query,
    suggested_chart_type, x_axis, y_axis, title, color_by
  }
}];

// Parse Groq chart response and inject full data
const groqResponse = $input.first().json;
const prevData = $('Code — Build Chart Prompt').first().json;

if (prevData.__skip_chart || prevData.error) {
  return [{ json: prevData }];
}

const content = groqResponse.choices?.[0]?.message?.content?.trim() || '';
const cleaned = content.replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();
const match = cleaned.match(/\{[\s\S]*\}/);

if (!match) throw new Error('No JSON in chart response: ' + content.slice(0, 200));

let parsed;
try { parsed = JSON.parse(match[0]); }
catch (e) { throw new Error('Chart JSON parse error: ' + match[0].slice(0, 200)); }

const charts = (parsed.charts || []).map(c => ({
  ...c,
  data: prevData.rows,
  sql: prevData.sql,
  row_count: prevData.row_count
}));

if (!charts.length) throw new Error('Groq returned empty charts array');

return [{ json: { charts, error: false } }];

// Final validation and shape normalisation
const input = $input.first().json;

if (input.error) {
  return [{ json: {
    error: true,
    message: input.message || 'Could not answer this question. Try rephrasing.',
    charts: []
  }}];
}

const VALID = new Set(['bar','line','area','pie','scatter','donut']);

const safeCharts = (input.charts || []).map(chart => {
  const ct = (chart.chart_type || 'bar').toLowerCase();
  const keys = chart.data?.length > 0 ? Object.keys(chart.data[0]) : [];
  const xKey = keys.includes(chart.x_axis) ? chart.x_axis : keys[0] || 'x';
  const yKey = keys.includes(chart.y_axis) ? chart.y_axis : keys[1] || 'y';

  return {
    title: chart.title || 'Analysis',
    chart_type: VALID.has(ct) ? ct : 'bar',
    x_axis: xKey,
    y_axis: yKey,
    color_by: chart.color_by || null,
    data: chart.data || [],
    sql: chart.sql || '',
    row_count: chart.row_count || (chart.data?.length ?? 0),
    insight: chart.insight || '',
    follow_up_suggestions: (chart.follow_up_suggestions || []).slice(0, 3)
  };
});

if (!safeCharts.length) {
  return [{ json: {
    error: true,
    message: 'No charts were generated. Try a more specific question.',
    charts: []
  }}];
}

return [{ json: { charts: safeCharts, error: false } }];
